class Solution {
    long mergeSort(int[] arr,int left,int right){
        if(left>=right) return 0;
        int mid=(left+right)/2;
        long count=0;
        count+=mergeSort(arr,left,mid);
        count+=mergeSort(arr,mid+1,right);
        count+=merge(arr,left,mid,right);
        return count;
    }

    long merge(int[] arr,int left,int mid,int right){
        ArrayList<Integer> temp=new ArrayList<>();
        int i=left,j=mid+1;
        long inv=0;
        while(i<=mid && j<=right){
            if(arr[i]<=arr[j]) temp.add(arr[i++]);
            else{
                temp.add(arr[j++]);
                inv += (mid-i+1);
            }
        }
        while(i<=mid) temp.add(arr[i++]);
        while(j<=right) temp.add(arr[j++]);
        for(int k=left;k<=right;k++)
            arr[k]=temp.get(k-left);
        return inv;
    }

    public long inversionCount(int[] arr){
        return mergeSort(arr,0,arr.length-1);
    }
}

